module top_module(
    input clk,
    input reset,
    input dir,
    output reg [4:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 5'b00000
            q <= 5'b00000;
        end else if (dir) begin
            // Up counter
            q <= q + 1;
        end else begin
            // Down counter
            q <= q - 1;
        end
    end

endmodule
